AGENT_LOOP analyze_stock_1
  MAX_ITERATIONS 2
  ARTIFACTS ".lgwf/loops/analyze_stock_1"
  STATUS state.agent_loop.analyze_stock_1.status
  REPORT state.agent_loop.analyze_stock_1.report
  ON_MAX wait_human ON_ERROR wait_human {
  DIAGNOSE CODEX diagnose_stock_1
    PROMPT_REF "02_reason/agents/prompt.md"
    RESULT state.agent_loop.analyze_stock_1.current.diagnosis;
  PLAN CODEX plan_stock_1
    PROMPT_REF "02_reason/agents/prompt.md"
    RESULT state.agent_loop.analyze_stock_1.current.plan;
  ACT CODEX act_stock_1
    PROMPT_REF "03_act/agents/prompt.md"
    RESULT state.agent_loop.analyze_stock_1.current.action;
  OBSERVE CODEX observe_stock_1
    PROMPT_REF "04_observe/agents/prompt.md"
    RESULT state.agent_loop.analyze_stock_1.current.observation;
  VERIFY PY verify_stock_1_loop
    SCRIPT "06_verify/scripts/agent_loop_verify.py"
    RESULT state.agent_loop.analyze_stock_1.current.verification;
  DECIDE PY decide_stock_1_loop
    SCRIPT "05_decide/scripts/agent_loop_decide.py"
    RESULT state.agent_loop.analyze_stock_1.current.decision;
};
